    19→//! Money Crate Collision Module
    20→//! 
    21→//! This crate provides money to the player who collects it. The amount can be
    22→//! enhanced by certain upgrades that the player has researched.
    23→
    24→use std::sync::{Arc, Mutex};
    25→use std::collections::HashMap;
    26→use crate::common::*;
