    30→/// Upgrade pair structure for bonus calculations
    31→#[derive(Debug, Clone, PartialEq)]
    32→pub struct UpgradePair {
    33→    /// Type/name of the upgrade
    34→    pub upgrade_type: String,
    35→    /// Bonus amount provided by this upgrade
    36→    pub amount: i32,
    37→}
    38→
    39→impl UpgradePair {
    40→    pub fn new(upgrade_type: String, amount: i32) -> Self {
    41→        Self {
    42→            upgrade_type,
    43→            amount,
    44→        }
    45→    }
    46→}
