    48→/// Configuration data for MoneyCrateCollide
    49→#[derive(Debug, Clone)]
    50→pub struct MoneyCrateCollideModuleData {
    51→    /// Base crate collision data
    52→    pub base: CrateCollideModuleData,
    53→    /// Base amount of money provided by this crate
    54→    pub money_provided: u32,
    55→    /// List of upgrade pairs that provide bonus money
    56→    pub upgrade_boosts: Vec<UpgradePair>,
    57→}
    58→
    59→impl MoneyCrateCollideModuleData {
    60→    pub fn new() -> Self {
    61→        Self {
    62→            base: CrateCollideModuleData::new(),
    63→            money_provided: 0,
    64→            upgrade_boosts: Vec::new(),
    65→        }
    66→    }
    67→    
    68→    pub fn with_money_amount(mut self, amount: u32) -> Self {
    69→        self.money_provided = amount;
    70→        self
    71→    }
    72→    
    73→    pub fn with_upgrade_boost(mut self, upgrade_type: String, bonus_amount: i32) -> Self {
    74→        self.upgrade_boosts.push(UpgradePair::new(upgrade_type, bonus_amount));
    75→        self
    76→    }
    77→    
    78→    pub fn with_upgrade_boosts(mut self, boosts: Vec<UpgradePair>) -> Self {
    79→        self.upgrade_boosts = boosts;
    80→        self
    81→    }
    82→}
    83→
    84→impl Default for MoneyCrateCollideModuleData {
    85→    fn default() -> Self {
    86→        Self::new()
    87→    }
    88→}
