    90→/// Money collection statistics
    91→#[derive(Debug, Clone)]
    92→pub struct MoneyCollectionStats {
    93→    /// Base money amount collected
    94→    pub base_amount: u32,
    95→    /// Bonus money from upgrades
    96→    pub bonus_amount: i32,
    97→    /// Total money collected
    98→    pub total_amount: u32,
    99→    /// Upgrades that contributed to the bonus
   100→    pub contributing_upgrades: Vec<String>,
   101→    /// Time when money was collected
   102→    pub collection_time: u64,
   103→}
   104→
   105→impl MoneyCollectionStats {
   106→    pub fn new(base_amount: u32, bonus_amount: i32, contributing_upgrades: Vec<String>) -> Self {
   107→        let total_amount = if bonus_amount < 0 {
   108→            base_amount.saturating_sub((-bonus_amount) as u32)
   109→        } else {
   110→            base_amount.saturating_add(bonus_amount as u32)
   111→        };
   112→        
   113→        Self {
   114→            base_amount,
   115→            bonus_amount,
   116→            total_amount,
   117→            contributing_upgrades,
   118→            collection_time: 0,
   119→        }
   120→    }
   121→}
   122→
   123→/// Money collection state
   124→#[derive(Debug)]
   125→struct MoneyCollectionState {
   126→    /// Whether money collection is in progress
   127→    is_collecting: bool,
   128→    /// ID of the collecting player
   129→    collecting_player_id: Option<PlayerId>,
   130→    /// Collection start time
   131→    collection_start_time: u64,
   132→    /// Statistics from the last collection
   133→    last_collection_stats: Option<MoneyCollectionStats>,
   134→}
