   136→/// Money Crate Collide implementation
   137→pub struct MoneyCrateCollide {
   138→    /// Base crate collision functionality
   139→    base_crate: CrateCollide,
   140→    /// Module-specific configuration
   141→    module_data: MoneyCrateCollideModuleData,
   142→    /// Thread-safe collection state
   143→    state: Arc<Mutex<MoneyCollectionState>>,
   144→}
   145→
   146→impl MoneyCrateCollide {
   147→    pub fn new(object_id: ObjectID, module_data: MoneyCrateCollideModuleData) -> Self {
   148→        Self {
   149→            base_crate: CrateCollide::new(object_id, module_data.base.clone()),
   150→            module_data,
   151→            state: Arc::new(Mutex::new(MoneyCollectionState {
   152→                is_collecting: false,
   153→                collecting_player_id: None,
   154→                collection_start_time: 0,
   155→                last_collection_stats: None,
   156→            })),
   157→        }
   158→    }
   159→    
   160→    pub fn get_module_data(&self) -> &MoneyCrateCollideModuleData {
   161→        &self.module_data
   162→    }
   163→    
   164→    /// Execute the money collection process
   165→    pub fn execute_money_collection(&mut self, other: &dyn GameObject) -> Result<bool, CollisionError> {
   166→        let player_id = other.get_controlling_player();
   167→        
   168→        // Start collection state tracking
   169→        {
   170→            let mut state = self.state.lock().map_err(|e| 
   171→                CollisionError::InvalidObject(format!("Failed to acquire state lock: {}", e))
   172→            )?;
   173→            state.is_collecting = true;
   174→            state.collecting_player_id = Some(player_id);
   175→            state.collection_start_time = self.get_current_time()?;
   176→        }
   177→        
   178→        // Calculate total money amount including upgrades
   179→        let base_money = self.module_data.money_provided;
   180→        let (upgrade_bonus, contributing_upgrades) = self.get_upgraded_supply_boost(other)?;
   181→        
   182→        let total_money = if upgrade_bonus < 0 {
   183→            base_money.saturating_sub((-upgrade_bonus) as u32)
   184→        } else {
   185→            base_money.saturating_add(upgrade_bonus as u32)
   186→        };
   187→        
   188→        // Deposit money to player's account
   189→        self.deposit_money_to_player(player_id, total_money)?;
   190→        
   191→        // Add to player's score
   192→        self.add_money_earned_to_score(player_id, total_money)?;
   193→        
   194→        // Play money collection audio
   195→        self.play_money_audio(other)?;
   196→        
   197→        // Create collection statistics
   198→        let collection_stats = MoneyCollectionStats::new(
   199→            base_money,
   200→            upgrade_bonus,
   201→            contributing_upgrades,
   202→        );
   203→        
   204→        // Store collection statistics
   205→        {
   206→            let mut state = self.state.lock().map_err(|e| 
   207→                CollisionError::InvalidObject(format!("Failed to acquire state lock: {}", e))
   208→            )?;
   209→            state.is_collecting = false;
   210→            state.last_collection_stats = Some(collection_stats);
   211→        }
   212→        
   213→        Ok(true)
   214→    }
   215→    
   216→    /// Calculate upgrade-based money boost
   217→    fn get_upgraded_supply_boost(&self, other: &dyn GameObject) -> Result<(i32, Vec<String>), CollisionError> {
   218→        let player_id = other.get_controlling_player();
   219→        let mut total_boost = 0i32;
   220→        let mut contributing_upgrades = Vec::new();
   221→        
   222→        // Loop through upgrade pairs and check if player has them
   223→        for upgrade_pair in &self.module_data.upgrade_boosts {
   224→            if self.player_has_upgrade(player_id, &upgrade_pair.upgrade_type)? {
   225→                total_boost += upgrade_pair.amount;
   226→                contributing_upgrades.push(upgrade_pair.upgrade_type.clone());
   227→            }
   228→        }
   229→        
   230→        Ok((total_boost, contributing_upgrades))
   231→    }
   232→    
   233→    /// Get the last collection statistics
   234→    pub fn get_last_collection_stats(&self) -> Result<Option<MoneyCollectionStats>, CollisionError> {
   235→        let state = self.state.lock().map_err(|e| 
   236→            CollisionError::InvalidObject(format!("Failed to acquire state lock: {}", e))
   237→        )?;
   238→        Ok(state.last_collection_stats.clone())
   239→    }
   240→    
   241→    /// Check if currently collecting money
   242→    pub fn is_collecting(&self) -> Result<bool, CollisionError> {
   243→        let state = self.state.lock().map_err(|e| 
   244→            CollisionError::InvalidObject(format!("Failed to acquire state lock: {}", e))
   245→        )?;
   246→        Ok(state.is_collecting)
   247→    }
   248→    
   249→    /// Get the player currently collecting (if any)
   250→    pub fn get_collecting_player(&self) -> Result<Option<PlayerId>, CollisionError> {
   251→        let state = self.state.lock().map_err(|e| 
   252→            CollisionError::InvalidObject(format!("Failed to acquire state lock: {}", e))
   253→        )?;
   254→        Ok(state.collecting_player_id)
   255→    }
   256→    
   257→    /// Calculate the total money this crate would provide to a specific player
   258→    pub fn calculate_total_money_for_player(&self, player_id: PlayerId) -> Result<u32, CollisionError> {
   259→        let base_money = self.module_data.money_provided;
   260→        let mut total_boost = 0i32;
   261→        
   262→        // Calculate upgrade bonuses
   263→        for upgrade_pair in &self.module_data.upgrade_boosts {
   264→            if self.player_has_upgrade(player_id, &upgrade_pair.upgrade_type)? {
   265→                total_boost += upgrade_pair.amount;
   266→            }
   267→        }
   268→        
   269→        let total_money = if total_boost < 0 {
   270→            base_money.saturating_sub((-total_boost) as u32)
   271→        } else {
   272→            base_money.saturating_add(total_boost as u32)
   273→        };
   274→        
   275→        Ok(total_money)
   276→    }
   277→    
   278→    // Helper methods that would interface with the game engine
   279→    fn get_current_time(&self) -> Result<u64, CollisionError> {
   280→        // Would get current game time
   281→        Ok(0)
   282→    }
   283→    
   284→    fn player_has_upgrade(&self, _player_id: PlayerId, _upgrade_type: &str) -> Result<bool, CollisionError> {
   285→        // Would check if player has completed the specified upgrade
   286→        Ok(false) // Default to no upgrades for testing
   287→    }
   288→    
   289→    fn deposit_money_to_player(&self, _player_id: PlayerId, _amount: u32) -> Result<(), CollisionError> {
   290→        // Would add money to player's resource pool
   291→        Ok(())
   292→    }
   293→    
   294→    fn add_money_earned_to_score(&self, _player_id: PlayerId, _amount: u32) -> Result<(), CollisionError> {
   295→        // Would add to player's score statistics
   296→        Ok(())
   297→    }
   298→    
   299→    fn play_money_audio(&self, other: &dyn GameObject) -> Result<(), CollisionError> {
   300→        // Would play "CrateMoney" audio event at object position
   301→        let _position = other.get_position();
   302→        Ok(())
   303→    }
   304→}
   305→
   306→impl CrateCollideBehavior for MoneyCrateCollide {
   307→    fn execute_crate_behavior(&mut self, other: &dyn GameObject) -> Result<bool, CollisionError> {
   308→        self.execute_money_collection(other)
   309→    }
   310→    
   311→    fn is_valid_to_execute(&self, other: &dyn GameObject) -> bool {
   312→        // Use base validation - money collection doesn't require additional restrictions
   313→        self.base_crate.is_valid_to_execute(other)
   314→    }
   315→}
