    31→/// Configuration data for HealCrateCollide
    32→/// 
    33→/// This module uses only the base CrateCollideModuleData as it doesn't
    34→/// require any additional configuration parameters.
    35→#[derive(Debug, Clone)]
    36→pub struct HealCrateCollideModuleData {
    37→    /// Base crate collision data
    38→    pub base: CrateCollideModuleData,
    39→    /// Optional healing amount multiplier (1.0 = full heal, 0.5 = half heal, etc.)
    40→    pub heal_multiplier: f32,
    41→    /// Whether to heal only units or include structures
    42→    pub heal_structures: bool,
    43→    /// Maximum range for healing effect (0 = unlimited)
    44→    pub heal_range: f32,
    45→}
    46→
    47→impl HealCrateCollideModuleData {
    48→    pub fn new() -> Self {
    49→        Self {
    50→            base: CrateCollideModuleData::new(),
    51→            heal_multiplier: 1.0, // Full heal by default
    52→            heal_structures: true, // Heal structures as well
    53→            heal_range: 0.0, // Unlimited range by default
    54→        }
    55→    }
    56→    
    57→    pub fn with_heal_multiplier(mut self, multiplier: f32) -> Self {
    58→        self.heal_multiplier = multiplier.max(0.0).min(1.0); // Clamp between 0 and 1
    59→        self
    60→    }
    61→    
    62→    pub fn with_heal_structures(mut self, heal_structures: bool) -> Self {
    63→        self.heal_structures = heal_structures;
    64→        self
    65→    }
    66→    
    67→    pub fn with_heal_range(mut self, range: f32) -> Self {
    68→        self.heal_range = range.max(0.0); // Cannot be negative
    69→        self
    70→    }
    71→}
    72→
    73→impl Default for HealCrateCollideModuleData {
    74→    fn default() -> Self {
    75→        Self::new()
    76→    }
    77→}
