   116→/// Heal Crate Collide implementation
   117→pub struct HealCrateCollide {
   118→    /// Base crate collision functionality
   119→    base_crate: CrateCollide,
   120→    /// Module-specific configuration
   121→    module_data: HealCrateCollideModuleData,
   122→    /// Thread-safe healing state
   123→    state: Arc<Mutex<HealState>>,
   124→}
   125→
   126→impl HealCrateCollide {
   127→    pub fn new(object_id: ObjectID, module_data: HealCrateCollideModuleData) -> Self {
   128→        Self {
   129→            base_crate: CrateCollide::new(object_id, module_data.base.clone()),
   130→            module_data,
   131→            state: Arc::new(Mutex::new(HealState {
   132→                is_healing: false,
   133→                target_player_id: None,
   134→                heal_start_time: 0,
   135→                last_healing_stats: None,
   136→            })),
   137→        }
   138→    }
   139→    
   140→    pub fn get_module_data(&self) -> &HealCrateCollideModuleData {
   141→        &self.module_data
   142→    }
   143→    
   144→    /// Execute the healing process for all objects owned by the player
   145→    pub fn execute_healing(&mut self, other: &dyn GameObject) -> Result<bool, CollisionError> {
   146→        let player_id = other.get_controlling_player();
   147→        
   148→        // Start healing state tracking
   149→        {
   150→            let mut state = self.state.lock().map_err(|e| 
   151→                CollisionError::InvalidObject(format!("Failed to acquire state lock: {}", e))
   152→            )?;
   153→            state.is_healing = true;
   154→            state.target_player_id = Some(player_id);
   155→            state.heal_start_time = self.get_current_time()?;
   156→        }
   157→        
   158→        // Heal all objects owned by the player
   159→        let healing_stats = self.heal_all_player_objects(player_id, &other.get_position())?;
   160→        
   161→        // Play healing audio effect
   162→        self.play_heal_audio(&other.get_position())?;
   163→        
   164→        // Store healing statistics
   165→        {
   166→            let mut state = self.state.lock().map_err(|e| 
   167→                CollisionError::InvalidObject(format!("Failed to acquire state lock: {}", e))
   168→            )?;
   169→            state.is_healing = false;
   170→            state.last_healing_stats = Some(healing_stats);
   171→        }
   172→        
   173→        Ok(true)
   174→    }
   175→    
   176→    /// Heal all objects owned by a specific player
   177→    fn heal_all_player_objects(&self, player_id: PlayerId, crate_position: &Coord3D) -> Result<HealingStats, CollisionError> {
   178→        let mut stats = HealingStats::new();
   179→        stats.heal_time = self.get_current_time()?;
   180→        
   181→        // Get all objects owned by the player
   182→        let player_objects = self.get_all_player_objects(player_id)?;
   183→        
   184→        for object in player_objects {
   185→            // Skip dead objects
   186→            if object.is_effectively_dead() {
   187→                continue;
   188→            }
   189→            
   190→            // Check range if specified
   191→            if self.module_data.heal_range > 0.0 {
   192→                let distance = crate_position.distance_to(&object.get_position());
   193→                if distance > self.module_data.heal_range {
   194→                    continue;
   195→                }
   196→            }
   197→            
   198→            // Check if we should heal structures
   199→            if self.is_structure(&object) && !self.module_data.heal_structures {
   200→                continue;
   201→            }
   202→            
   203→            // Perform healing
   204→            let health_restored = self.heal_object(&object)?;
   205→            
   206→            if health_restored > 0.0 {
   207→                stats.total_health_restored += health_restored;
   208→                
   209→                if self.is_structure(&object) {
   210→                    stats.structures_healed += 1;
   211→                } else {
   212→                    stats.units_healed += 1;
   213→                }
   214→            }
   215→        }
   216→        
   217→        Ok(stats)
   218→    }
   219→    
   220→    /// Heal a specific object
   221→    fn heal_object(&self, object: &dyn GameObject) -> Result<f32, CollisionError> {
   222→        let current_health = self.get_object_health(object)?;
   223→        let max_health = self.get_object_max_health(object)?;
   224→        
   225→        if current_health >= max_health {
   226→            return Ok(0.0); // Already at full health
   227→        }
   228→        
   229→        let heal_amount = (max_health - current_health) * self.module_data.heal_multiplier;
   230→        let new_health = current_health + heal_amount;
   231→        
   232→        self.set_object_health(object, new_health)?;
   233→        
   234→        // Play healing FX on the object
   235→        self.play_heal_fx_on_object(object)?;
   236→        
   237→        Ok(heal_amount)
   238→    }
   239→    
   240→    /// Get the last healing statistics
   241→    pub fn get_last_healing_stats(&self) -> Result<Option<HealingStats>, CollisionError> {
   242→        let state = self.state.lock().map_err(|e| 
   243→            CollisionError::InvalidObject(format!("Failed to acquire state lock: {}", e))
   244→        )?;
   245→        Ok(state.last_healing_stats.clone())
   246→    }
   247→    
   248→    /// Check if currently healing
   249→    pub fn is_healing(&self) -> Result<bool, CollisionError> {
   250→        let state = self.state.lock().map_err(|e| 
   251→            CollisionError::InvalidObject(format!("Failed to acquire state lock: {}", e))
   252→        )?;
   253→        Ok(state.is_healing)
   254→    }
   255→    
   256→    /// Get the player being healed (if any)
   257→    pub fn get_target_player(&self) -> Result<Option<PlayerId>, CollisionError> {
   258→        let state = self.state.lock().map_err(|e| 
   259→            CollisionError::InvalidObject(format!("Failed to acquire state lock: {}", e))
   260→        )?;
   261→        Ok(state.target_player_id)
   262→    }
